/**
 * @summary Get message history for a session
 */
export const getGetSessionMessagesUrl = (
  id: string,
  params?: GetSessionMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/sessions/${id}/messages?${stringifiedParams}`
    : `/api/sessions/${id}/messages`;
};

export const getSessionMessages = async (
  id: string,
  params?: GetSessionMessagesParams,
  options?: RequestInit,
): Promise<Message[]> => {
  return customFetch<Message[]>(getGetSessionMessagesUrl(id, params), {
    ...options,
    method: "GET",
  });
};

